#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, K; scanf("%d %d", &N, &K);
        long long loss = 0;
        for(int i=0;i<N;i++){
            int p; scanf("%d", &p);
            if(p > K) loss += (long long)(p - K);
        }
        printf("%lld\n", loss);
    }
    return 0;
}

