import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it); K = next(it)
        loss = 0
        for _ in range(N):
            p = next(it)
            if p > K:
                loss += p - K
        out_lines.append(str(loss))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

